-- Bean catalog seed generated from /mnt/data/bean_data.csv
-- 기준: product는 전체 54개 저장, 싱글 오리진은 실제 bean으로 저장, 블렌드는 사용자 확인에 따라 bean.region='blend'로 저장, 콜롬비아 엘 파라이소 리치피치는 동일 lot으로 병합
-- 사용자 확인 반영: 8개 싱글 오리진/동일 lot 확정 항목과 19개 블렌드 region=blend 처리 반영
SET NAMES utf8mb4;
START TRANSACTION;

    AS new_row
ON DUPLICATE KEY UPDATE name_ko=new_row.name_ko, name_en=new_row.name_en, homepage_url=new_row.homepage_url, description=new_row.description, updated_at=new_row.updated_at;
    AS new_row
ON DUPLICATE KEY UPDATE roaster_id=new_row.roaster_id, name_ko=new_row.name_ko, name_en=new_row.name_en, roasting_level=new_row.roasting_level, agtron_min=new_row.agtron_min, agtron_max=new_row.agtron_max, acidity=new_row.acidity, sweetness=new_row.sweetness, body=new_row.body, balance=new_row.balance, description=new_row.description, product_url=new_row.product_url, updated_at=new_row.updated_at;
    AS new_row
ON DUPLICATE KEY UPDATE name_ko=new_row.name_ko, name_en=new_row.name_en, process=new_row.process, origin=new_row.origin, region=new_row.region, variety=new_row.variety, altitude_min=new_row.altitude_min, altitude_max=new_row.altitude_max, updated_at=new_row.updated_at;
    AS new_row
ON DUPLICATE KEY UPDATE product_id=new_row.product_id, bean_id=new_row.bean_id, updated_at=new_row.updated_at;
    AS new_row
ON DUPLICATE KEY UPDATE flavor_category=new_row.flavor_category, name_ko=new_row.name_ko, name_en=new_row.name_en, flavor_image_url=new_row.flavor_image_url, updated_at=new_row.updated_at;
    AS new_row
ON DUPLICATE KEY UPDATE product_id=new_row.product_id, flavor_note_id=new_row.flavor_note_id, updated_at=new_row.updated_at;
COMMIT;
